import React, { useState, useEffect, useRef } from 'react';

export default function MultiSelect({ options, value, onChange }) {
  const [open, setOpen] = useState(false);
  const root = useRef(null);

  useEffect(() => {
    const onDoc = (e) => {
      if (root.current && !root.current.contains(e.target)) setOpen(false);
    };
    document.addEventListener('mousedown', onDoc);
    return () => document.removeEventListener('mousedown', onDoc);
  }, []);

  const toggle = (v) => {
    const next = new Set(value);
    if (next.has(v)) next.delete(v);
    else next.add(v);
    onChange([...next]);
  };

  const label = value.length === 0 ? 'Select…' : `${value.length} selected`;

  return (
    <div ref={root} style={{ position: 'relative', width: 240 }}>
      <button
        onClick={() => setOpen((o) => !o)}
        aria-haspopup="listbox"
        aria-expanded={open}
        style={{ width: '100%', textAlign: 'left', padding: '10px 12px', border: '1px solid #ccc', borderRadius: 8, background: '#fff', cursor: 'pointer', display: 'flex', justifyContent: 'space-between' }}
      >
        <span style={{ color: value.length ? '#111' : '#888' }}>{label}</span>
        <span>▾</span>
      </button>

      {open && (
        <ul
          role="listbox"
          aria-multiselectable="true"
          style={{ position: 'absolute', top: '100%', left: 0, right: 0, margin: '4px 0 0', padding: 4, listStyle: 'none', border: '1px solid #ddd', borderRadius: 8, background: '#fff', boxShadow: '0 6px 20px rgba(0,0,0,0.12)', zIndex: 10 }}
        >
          {options.map((o) => {
            const checked = value.includes(o.value);
            return (
              <li
                key={o.value}
                role="option"
                aria-selected={checked}
                onClick={() => toggle(o.value)}
                style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '8px 10px', cursor: 'pointer', borderRadius: 6, background: checked ? '#eef2ff' : '#fff' }}
              >
                <input type="checkbox" checked={checked} readOnly />
                {o.label}
              </li>
            );
          })}
        </ul>
      )}
    </div>
  );
}

