import { Component, Input, Output, EventEmitter, HostListener, ElementRef } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Option { value: string; label: string; }

@Component({
  selector: 'app-multi-select',
  template: `
    <div style="position: relative; width: 240px;">
      <button
        (click)="open = !open; $event.stopPropagation()"
        aria-haspopup="listbox"
        [attr.aria-expanded]="open"
        style="width: 100%; text-align: left; padding: 10px 12px; border: 1px solid #ccc; border-radius: 8px; background: #fff; cursor: pointer; display: flex; justify-content: space-between;"
      >
        <span [style.color]="selected.length ? '#111' : '#888'">{{ selected.length ? selected.length + ' selected' : 'Select…' }}</span>
        <span>▾</span>
      </button>

      <ul
        *ngIf="open"
        role="listbox"
        aria-multiselectable="true"
        style="position: absolute; top: 100%; left: 0; right: 0; margin: 4px 0 0; padding: 4px; list-style: none; border: 1px solid #ddd; border-radius: 8px; background: #fff; box-shadow: 0 6px 20px rgba(0,0,0,0.12); z-index: 10;"
      >
        <li
          *ngFor="let o of options"
          role="option"
          [attr.aria-selected]="isOn(o.value)"
          (click)="toggle(o.value)"
          [style.background]="isOn(o.value) ? '#eef2ff' : '#fff'"
          style="display: flex; align-items: center; gap: 8px; padding: 8px 10px; cursor: pointer; border-radius: 6px;"
        >
          <input type="checkbox" [checked]="isOn(o.value)" readonly />
          {{ o.label }}
        </li>
      </ul>
    </div>
  `,
})
export class MultiSelectComponent {
  @Input() options: Option[] = [];
  @Input() selected: string[] = [];
  @Output() selectedChange = new EventEmitter<string[]>();
  open = false;

  constructor(private host: ElementRef<HTMLElement>) {}

  isOn(v: string): boolean {
    return this.selected.indexOf(v) !== -1;
  }

  toggle(v: string): void {
    const set = new Set(this.selected);
    if (set.has(v)) {
      set.delete(v);
    } else {
      set.add(v);
    }
    this.selectedChange.emit([...set]);
  }

  @HostListener('document:click', ['$event'])
  onDoc(e: MouseEvent): void {
    if (!this.host.nativeElement.contains(e.target as Node)) {
      this.open = false;
    }
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Multi-select Demo</h1>
      <app-multi-select [options]="options" [selected]="selected" (selectedChange)="selected = $event"></app-multi-select>
      <p style="color: #666;">Selected: {{ selected.join(', ') || '(none)' }}</p>
    </div>
  `,
})
export class AppComponent {
  options: Option[] = [
    { value: 'js', label: 'JavaScript' },
    { value: 'ts', label: 'TypeScript' },
    { value: 'py', label: 'Python' },
    { value: 'go', label: 'Go' },
    { value: 'rs', label: 'Rust' },
  ];
  selected: string[] = ['ts'];
}

@NgModule({
  declarations: [AppComponent, MultiSelectComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
